function solve(nums) {
    // The problem asks for the maximum number of fixed points we can achieve
    // by deleting zero or more elements, where elements shift left upon deletion.
    // If we keep a subsequence of the original array, say at original indices i_1, i_2, ..., i_k,
    // where i_1 < i_2 < ... < i_k, the new array has length k.
    // The element originally at nums[i_j] will end up at the new index j-1 (0-indexed).
    // For this element to be a fixed point, we must have:
    // nums[i_j] = j - 1

    // Let's rephrase the condition. We are looking for the longest subsequence of indices 
    // i_1, i_2, ..., i_k (where 0 <= i_1 < i_2 < ... < i_k < nums.length)
    // such that for every j from 1 to k, nums[i_j] = j - 1.
    // Using 0-based indexing for j (0 <= j < k):
    // We want to find the longest subsequence of indices i_0, i_1, ..., i_{k-1}
    // such that nums[i_j] = j.

    // This is a classic Longest Increasing Subsequence (LIS) variant, or more simply,
    // a greedy selection problem because the target value for the j-th element (0-indexed)
    // is strictly determined by j itself.

    let maxFixedPoints = 0;
    let requiredValue = 0; // This represents the target index (the desired value for the element)

    // We iterate through the original array.
    for (let i = 0; i < nums.length; i++) {
        // If the current element nums[i] matches the value required for the next fixed point (requiredValue),
        // we choose to keep this element. By keeping it, it becomes the next element in our subsequence,
        // and its new index will be requiredValue.
        if (nums[i] === requiredValue) {
            // We found a valid element for the current fixed point position.
            maxFixedPoints++;
            // The next fixed point we are looking for must be at the next position,
            // so its value must be requiredValue + 1.
            requiredValue++;
        }
    }

    return maxFixedPoints;
}

